<?php

namespace App\Helpers;

class MenuHelper
{
    public static function getMainNavItems()
    {
        $user = auth()->user();

        return array_filter([
            [
                'icon' => 'dashboard',
                'name' => 'Dashboard',
                'path' => '/dashboard',
            ],
            [
                'name' => 'Front Desk',
                'icon' => 'booking',
                'subItems' => array_filter([
                    ['name' => 'New Booking', 'path' => '/createIdentity'],
                    ['name' => 'All Bookings', 'path' => '/transaction'],
                    ['name' => 'Calendar View', 'path' => '/calendar'],
                    ($user && $user->role !== 'receptionist') ? ['name' => 'Future Bookings', 'path' => '/transaction?status=future'] : null,
                ]),
            ],
            [
                'name' => 'Room Management',
                'icon' => 'rooms',
                'subItems' => [
                    ['name' => 'All Rooms', 'path' => '/room'],
                    ['name' => 'Room Types', 'path' => '/type'],
                    ['name' => 'Room Status', 'path' => '/roomstatus'],
                    ['name' => 'Facilities', 'path' => '/facility'],
                ],
            ],
            [
                'name' => 'Customers',
                'icon' => 'customers',
                'path' => '/customer',
            ],
            [
                'name' => 'Payments',
                'icon' => 'payments',
                'subItems' => [
                    ['name' => 'All Payments', 'path' => '/payment'],
                ],
            ],
            ($user && $user->role !== 'receptionist') ? [
                'name' => 'Reports',
                'icon' => 'charts',
                'subItems' => [
                    ['name' => 'Revenue Report', 'path' => '/blank'],
                    ['name' => 'Occupancy Report', 'path' => '/blank'],
                ],
            ] : null,
            ($user && $user->role === 'creator') ? [
                'icon' => 'authentication',
                'name' => 'System',
                'subItems' => [
                    ['name' => 'Users', 'path' => '/user'],
                    ['name' => 'Activity Log', 'path' => '/activity-log'],
                    ['name' => 'Feature Flags', 'path' => '/blank'],
                    ['name' => 'Settings', 'path' => '/blank'],
                ],
            ] : null,
        ]);
    }

    public static function getMenuGroups()
    {
        return [
            [
                'title' => 'Navigation',
                'items' => self::getMainNavItems()
            ],
        ];
    }

    public static function isActive($path)
    {
        return request()->is(ltrim($path, '/'));
    }

